import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_pkgs(data):
    result = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                key = (pname, pkg['id'])
                result[key] = pkg.get('resolvedVersion', pkg.get('requestedVersion','?'))
    return result

b = get_pkgs(baseline)
a = get_pkgs(after)
changes = []
for k in sorted(set(list(b.keys()) + list(a.keys()))):
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    if bv != av:
        changes.append((k[0], k[1], bv, av))
if changes:
    print('CHANGES:')
    for p, pkg, bv, av in changes:
        print(f'  {p}: {pkg} {bv} -> {av}')
else:
    print('No unexpected changes')

print()
print('ALL RESOLVED VERSIONS:')
for k in sorted(a.keys()):
    print(f'  {k[0]}: {k[1]} = {a[k]}')
"

